const PRISMA_TO_TS_TYPE: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Map a Prisma scalar type name to its TypeScript equivalent. */
export function scalarToTsType(prismaType: string): string {
  return PRISMA_TO_TS_TYPE[prismaType] ?? 'unknown'
}

/** Resolve the TypeScript type string for a DMMF field. */
export function fieldToTsType(field: ReadonlyDeep<DMMF.Field>): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = scalarToTsType(field.type)
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/** Determine whether a field is optional for create input (has default or is nullable). */
export function isOptionalForCreate(field: ReadonlyDeep<DMMF.Field>): boolean {
  return field.hasDefaultValue || !field.isRequired || field.isUpdatedAt === true || field.isGenerated === true
}

/** Generate an interface declaration from a list of property entries. */
export function renderInterface(name: string, properties: Array<{ name: string; type: string; optional: boolean }>): string {
  const lines = properties.map((p) => `  ${p.name}${p.optional ? '?' : ''}: ${p.type}`)
  return `export interface ${name} {\n${lines.join('\n')}\n}`
}

